mapper.select:
SELECT

FROM customer_info t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.customer_name LIKE CONCAT ('%',#{request.customerName},'%')


    AND t0.document_type  LIKE CONCAT ('%',#{request.documentType},'%')


    AND t0.document_code LIKE CONCAT ('%',#{request.documentCode},'%')


    AND t0.contacts  LIKE CONCAT ('%',#{request.contacts},'%')


    AND t0.contacts_phone  LIKE CONCAT ('%',#{request.contactsPhone},'%')


    AND t0.medium_source = #{request.mediumSource}


    AND t0.customer_source = #{request.customerSource}


    AND t0.intentional_assets = #{request.intentionalAssets}


    AND t0.remark = #{request.remark}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
